/**/ typeof cookiePrompt === 'function' && cookiePrompt("<div class=\"bbccookies-banner\">\n    <div class=\"b-g-m orb-banner-wrapper bbccookies-d\">\n            <div id=\"bbcprivacy\" style=\"display: none\">\n                <section id=\"bbcprivacy-prompt\" class=\"orb-banner b-r\" aria-labelledby=\"privacy-banner-title\">\n                    <div class=\"orb-banner-content\">\n                        <h2 class=\"orb-banner-title\" id=\"privacy-banner-title\">\n                            <span>We&#x27;ve updated our Privacy and Cookies Policy</span>\n                        </h2>\n                        <p dir=\"ltr\">We've made some important changes to our Privacy and Cookies Policy and we want you to know what this means for you and your data.</p>\n                    </div>\n                    <div class=\"orb-banner-options\">\n                                <button type=\"button\" id=\"bbcprivacy-continue-button\" class=\"banner-button\">\n                                    <span>OK</span>\n                                </button>\n                                <a href=\"<<bbcUrlPrefix>>/usingthebbc/your-data-matters\" class=\"banner-button-link\">\n                                    <span>Find out what&#x27;s changed</span>\n                                </a>\n                    </div>\n                </section>\n            </div>\n            <div id=\"bbccookies\" style=\"display: none\">\n                <section id=\"bbccookies-prompt\" class=\"orb-banner b-r\" aria-labelledby=\"cookies-banner-title\">\n                    <div class=\"orb-banner-content\">\n                        <h2 class=\"orb-banner-title\" id=\"cookies-banner-title\">\n                            <span>Cookies on the BBC website</span>\n                        </h2>\n                        <p dir=\"ltr\"><a href=\"<<bbcUrlPrefix>>/usingthebbc/cookies/what-do-i-need-to-know-about-cookies/\">We use cookies</a> to give you the best online experience.  Strictly necessary cookies are <strong>on</strong> by default.  Additional cookies are <strong>off</strong> by default.</p>\n                    </div>\n                    <div class=\"orb-banner-options\">\n                                <button type=\"button\" id=\"bbccookies-accept-button\" class=\"banner-button\">\n                                    <span>Accept additional cookies</span>\n                                </button>\n                                <button type=\"button\" id=\"bbccookies-reject-button\" class=\"banner-button\">\n                                    <span>Reject additional cookies</span>\n                                </button>\n                                <a href=\"<<bbcUrlPrefix>>/usingthebbc/cookies/how-can-i-change-my-bbc-cookie-settings/\" class=\"banner-button-link\">\n                                    <span>Let me choose</span>\n                                </a>\n                    </div>\n                </section>\n            </div>\n    </div>\n</div>\n");